        const actor = vtkImageSlice.newInstance();
        const imageData = payload.imageData ?? createVTKImageDataFromImage(payload.image);
        ctx.display.activateRenderMode(ActorRenderMode.VTK_IMAGE);
        mapper.setInputData(imageData);
